# Winston: Structured Logging, Transports, and Log Levels

## Why Structured Logging Matters

When your Node.js application is running in production, `console.log` is not enough. You need logs that are searchable, filterable, and parseable by log aggregation tools like the ELK stack, Datadog, or Splunk. Structured logging means outputting log entries as JSON objects with consistent fields -- timestamp, level, message, and contextual metadata -- instead of arbitrary strings.

```
# Unstructured (useless at scale)
User logged in
Order placed for $49.99
Database connection failed

# Structured (searchable, filterable, alertable)
{"timestamp":"2025-03-15T10:30:00Z","level":"info","message":"User logged in","userId":"u_abc123","ip":"192.168.1.50","service":"auth"}
{"timestamp":"2025-03-15T10:30:01Z","level":"info","message":"Order placed","orderId":"ord_xyz","amount":49.99,"userId":"u_abc123","service":"orders"}
{"timestamp":"2025-03-15T10:30:02Z","level":"error","message":"Database connection failed","host":"db-primary","port":5432,"error":"ECONNREFUSED","service":"orders"}
```

## Installing Winston

```bash
npm install winston
```

## Basic Setup

```js
import winston from 'winston';

const logger = winston.createLogger({
  level: 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.json()
  ),
  defaultMeta: { service: 'my-api' },
  transports: [
    new winston.transports.Console(),
    new winston.transports.File({ filename: 'logs/error.log', level: 'error' }),
    new winston.transports.File({ filename: 'logs/combined.log' }),
  ],
});

// Usage
logger.info('Server started', { port: 3000 });
logger.error('Database connection failed', { host: 'localhost', error: 'ECONNREFUSED' });
logger.warn('Rate limit approaching', { userId: 'u_123', requests: 95, limit: 100 });
logger.debug('Query executed', { sql: 'SELECT * FROM users', duration: 42 });
```

## Log Levels

Winston uses the npm logging levels by default (RFC 5424 syslog levels are also available):

```
┌──────────┬────────┬──────────────────────────────────────────┐
│  Level   │ Number │ When to Use                              │
├──────────┼────────┼──────────────────────────────────────────┤
│ error    │   0    │ Application errors requiring attention   │
│ warn     │   1    │ Potential issues, degraded behavior      │
│ info     │   2    │ Normal operations, audit events          │
│ http     │   3    │ HTTP request/response logging            │
│ verbose  │   4    │ More detail than info, less than debug   │
│ debug    │   5    │ Development debugging, detailed traces   │
│ silly    │   6    │ Extremely verbose, rarely used           │
└──────────┴────────┴──────────────────────────────────────────┘

Setting level: 'info' means you see error, warn, and info.
Messages at debug and below are silently dropped.
```

## Formats

Winston formats are composable transforms that process log entries:

```js
import winston from 'winston';
const { combine, timestamp, json, colorize, printf, errors, metadata } = winston.format;

// JSON format for production (machine-readable)
const productionFormat = combine(
  timestamp({ format: 'YYYY-MM-DDTHH:mm:ss.SSSZ' }),
  errors({ stack: true }),  // capture stack traces
  json()
);

// Pretty format for development (human-readable)
const developmentFormat = combine(
  colorize({ all: true }),
  timestamp({ format: 'HH:mm:ss' }),
  printf(({ timestamp, level, message, service, ...meta }) => {
    const metaStr = Object.keys(meta).length ? JSON.stringify(meta, null, 2) : '';
    return `${timestamp} [${level}] ${message} ${metaStr}`;
  })
);

// Choose format based on environment
const logger = winston.createLogger({
  level: process.env.LOG_LEVEL || 'info',
  format: process.env.NODE_ENV === 'production'
    ? productionFormat
    : developmentFormat,
  defaultMeta: { service: 'my-api' },
  transports: [new winston.transports.Console()],
});
```

## Transports

Transports determine where log entries are sent:

```js
import winston from 'winston';
import 'winston-daily-rotate-file';  // npm install winston-daily-rotate-file

const logger = winston.createLogger({
  level: 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.json()
  ),
  transports: [
    // Console: always
    new winston.transports.Console({
      level: process.env.NODE_ENV === 'production' ? 'info' : 'debug',
    }),

    // Error file: only errors
    new winston.transports.File({
      filename: 'logs/error.log',
      level: 'error',
      maxsize: 10 * 1024 * 1024,  // 10MB
      maxFiles: 5,
    }),

    // Daily rotation: all logs
    new winston.transports.DailyRotateFile({
      filename: 'logs/app-%DATE%.log',
      datePattern: 'YYYY-MM-DD',
      maxSize: '20m',
      maxFiles: '14d',  // keep 14 days
      zippedArchive: true,
    }),
  ],
});
```

## Child Loggers and Contextual Logging

Child loggers inherit the parent's configuration but add context:

```js
// Create the root logger
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.json()
  ),
  defaultMeta: { service: 'my-api' },
  transports: [new winston.transports.Console()],
});

// Create a child logger for a specific module
const authLogger = logger.child({ module: 'auth' });
const orderLogger = logger.child({ module: 'orders' });

// Each log includes the module field automatically
authLogger.info('User logged in', { userId: 'u_123' });
// {"timestamp":"...","level":"info","message":"User logged in","service":"my-api","module":"auth","userId":"u_123"}

orderLogger.error('Payment failed', { orderId: 'o_456', reason: 'card_declined' });
// {"timestamp":"...","level":"error","message":"Payment failed","service":"my-api","module":"orders","orderId":"o_456","reason":"card_declined"}
```

## Express Integration with Request Context

```js
import express from 'express';
import crypto from 'node:crypto';
import winston from 'winston';

const logger = winston.createLogger({
  level: process.env.LOG_LEVEL || 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.json()
  ),
  defaultMeta: { service: 'my-api' },
  transports: [new winston.transports.Console()],
});

const app = express();

// Request logging middleware
app.use((req, res, next) => {
  // Generate or extract request ID
  const requestId = req.headers['x-request-id'] || crypto.randomUUID();
  req.requestId = requestId;
  res.setHeader('X-Request-ID', requestId);

  // Create a request-scoped child logger
  req.log = logger.child({
    requestId,
    method: req.method,
    url: req.originalUrl,
    ip: req.ip,
  });

  // Log request start
  req.log.info('Request received');

  // Log response when finished
  const startTime = Date.now();
  res.on('finish', () => {
    const duration = Date.now() - startTime;
    const logLevel = res.statusCode >= 500 ? 'error'
      : res.statusCode >= 400 ? 'warn'
      : 'info';

    req.log[logLevel]('Request completed', {
      statusCode: res.statusCode,
      duration,
      contentLength: res.get('Content-Length'),
    });
  });

  next();
});

// Use req.log in route handlers
app.get('/api/users/:id', async (req, res) => {
  req.log.info('Fetching user', { targetUserId: req.params.id });

  try {
    const user = await findUser(req.params.id);
    req.log.info('User found', { targetUserId: user.id });
    res.json(user);
  } catch (err) {
    req.log.error('Failed to fetch user', {
      targetUserId: req.params.id,
      error: err.message,
      stack: err.stack,
    });
    res.status(500).json({ error: 'Internal server error' });
  }
});
```

## Sensitive Data Redaction

Never log passwords, tokens, credit cards, or PII:

```js
const sensitiveKeys = ['password', 'token', 'authorization', 'cookie', 'secret', 'ssn', 'creditCard'];

const redactFormat = winston.format((info) => {
  // Deep clone to avoid mutating the original
  const redacted = JSON.parse(JSON.stringify(info));

  function redactObject(obj) {
    for (const key of Object.keys(obj)) {
      if (sensitiveKeys.some(sk => key.toLowerCase().includes(sk))) {
        obj[key] = '[REDACTED]';
      } else if (typeof obj[key] === 'object' && obj[key] !== null) {
        redactObject(obj[key]);
      }
    }
  }

  redactObject(redacted);
  return redacted;
});

const logger = winston.createLogger({
  format: winston.format.combine(
    redactFormat(),
    winston.format.timestamp(),
    winston.format.json()
  ),
  transports: [new winston.transports.Console()],
});

logger.info('Login attempt', {
  email: 'user@example.com',
  password: 'secret123',
  token: 'eyJhbG...',
});
// Output: {"email":"user@example.com","password":"[REDACTED]","token":"[REDACTED]"}
```

## Error Logging Best Practices

```js
// DO: Log errors with full context
try {
  await processOrder(orderId);
} catch (err) {
  logger.error('Order processing failed', {
    orderId,
    userId: req.user.id,
    error: err.message,
    stack: err.stack,
    code: err.code,
  });
}

// DON'T: Log just the error object
// logger.error(err);                    // Missing context
// logger.error('Error: ' + err);        // Loses stack trace
// logger.error(err.toString());          // Loses structured data

// DO: Use the errors format for automatic stack capture
const logger = winston.createLogger({
  format: winston.format.combine(
    winston.format.errors({ stack: true }),
    winston.format.timestamp(),
    winston.format.json()
  ),
  transports: [new winston.transports.Console()],
});

// Now you can pass Error objects directly
logger.error('Database query failed', { error: new Error('Connection timeout') });
```

## Testing with Winston

```js
import winston from 'winston';

// Create a silent logger for tests
const testLogger = winston.createLogger({
  silent: true,  // suppresses all output
});

// Or capture logs for assertions
class TestTransport extends winston.Transport {
  constructor(opts) {
    super(opts);
    this.logs = [];
  }

  log(info, callback) {
    this.logs.push(info);
    callback();
  }

  clear() {
    this.logs = [];
  }
}

// In your test
const testTransport = new TestTransport();
const logger = winston.createLogger({
  transports: [testTransport],
});

logger.info('test message', { key: 'value' });
assert(testTransport.logs.length === 1);
assert(testTransport.logs[0].message === 'test message');
```

## Production Configuration

A complete production-ready logger setup:

```js
import winston from 'winston';
import 'winston-daily-rotate-file';

const isProduction = process.env.NODE_ENV === 'production';

const logger = winston.createLogger({
  level: process.env.LOG_LEVEL || (isProduction ? 'info' : 'debug'),
  format: winston.format.combine(
    winston.format.timestamp({ format: 'YYYY-MM-DDTHH:mm:ss.SSSZ' }),
    winston.format.errors({ stack: true }),
    isProduction
      ? winston.format.json()
      : winston.format.combine(
          winston.format.colorize(),
          winston.format.printf(({ timestamp, level, message, ...meta }) => {
            const metaStr = Object.keys(meta).length
              ? '\n' + JSON.stringify(meta, null, 2)
              : '';
            return `${timestamp} ${level}: ${message}${metaStr}`;
          })
        )
  ),
  defaultMeta: {
    service: process.env.SERVICE_NAME || 'my-api',
    version: process.env.APP_VERSION || '1.0.0',
    environment: process.env.NODE_ENV || 'development',
  },
  transports: [
    new winston.transports.Console(),
    ...(isProduction ? [
      new winston.transports.DailyRotateFile({
        filename: 'logs/app-%DATE%.log',
        datePattern: 'YYYY-MM-DD',
        maxSize: '50m',
        maxFiles: '30d',
        zippedArchive: true,
      }),
      new winston.transports.DailyRotateFile({
        filename: 'logs/error-%DATE%.log',
        datePattern: 'YYYY-MM-DD',
        level: 'error',
        maxSize: '20m',
        maxFiles: '90d',
        zippedArchive: true,
      }),
    ] : []),
  ],
  // Handle uncaught exceptions and rejections
  exceptionHandlers: [
    new winston.transports.File({ filename: 'logs/exceptions.log' }),
  ],
  rejectionHandlers: [
    new winston.transports.File({ filename: 'logs/rejections.log' }),
  ],
});

export default logger;
```

## Summary

Winston is the most flexible logging library in the Node.js ecosystem. Its transport system lets you route logs to console, files, rotation, and external services simultaneously. Use JSON format in production, pretty-print in development, child loggers for contextual data, and always redact sensitive information. Combined with request ID tracking, Winston gives you the observability you need to debug production issues efficiently.

7.5.2.body:
# Pino: High-Performance JSON Logging

## Why Pino?

Pino is the fastest JSON logger for Node.js. While Winston is the most flexible, Pino is the most performant -- it produces structured JSON logs with minimal overhead, making it ideal for high-throughput applications where every millisecond counts.

The key difference: Winston formats and processes logs synchronously in the main thread. Pino defers serialization and output to a worker thread or separate process (via pino transports), keeping the event loop free.

```
┌─────────────────────────────────────────────────────┐
│              Logging Performance Comparison           │
├─────────────────────────────────────────────────────┤
│                                                     │
│  console.log    ████████████████████████  ~100%      │
│  Winston JSON   ██████████████████       ~75%        │
│  Bunyan         ██████████████           ~60%        │
│  Pino           ████                     ~15%        │
│                                                     │
│  (lower is better - % of event loop time consumed)  │
│                                                     │
│  Pino achieves this by:                             │
│  - Minimal serialization in the main thread         │
│  - No string formatting or interpolation            │
│  - Worker thread transports (pino.transport)        │
│  - Flat JSON output (no nested transforms)          │
│                                                     │
└─────────────────────────────────────────────────────┘
```

## Installing Pino

```bash
npm install pino
npm install pino-pretty --save-dev  # pretty-print for development
```

## Basic Setup

```js
import pino from 'pino';

const logger = pino({
  level: process.env.LOG_LEVEL || 'info',
});

logger.info('Server started');
logger.info({ port: 3000 }, 'Server started on port');
logger.error({ err: new Error('Connection failed') }, 'Database error');
logger.warn({ userId: 'u_123', limit: 100 }, 'Rate limit approaching');
logger.debug({ query: 'SELECT * FROM users' }, 'Query executed');
```

Output (newline-delimited JSON):
```json
{"level":30,"time":1710500000000,"pid":12345,"hostname":"server-1","msg":"Server started"}
{"level":30,"time":1710500000001,"pid":12345,"hostname":"server-1","port":3000,"msg":"Server started on port"}
```

## Pino's API Convention

Pino uses a different argument order than Winston. The metadata object comes first, the message string comes second:

```js
// Pino convention: context object FIRST, message SECOND
logger.info({ userId: 'u_123', action: 'login' }, 'User logged in');

// Just a message (no context)
logger.info('Simple message');

// Just context (no message)
logger.info({ event: 'startup', port: 3000 });

// WRONG: This does NOT work like Winston
// logger.info('message', { key: 'value' });  // second arg is ignored as merge object
```

## Log Levels

Pino uses numeric levels (lower = more severe):

```
┌──────────┬────────┬──────────────────────────────────┐
│  Level   │ Number │ Usage                            │
├──────────┼────────┼──────────────────────────────────┤
│ fatal    │   60   │ App is about to crash            │
│ error    │   50   │ Runtime errors, failed ops        │
│ warn     │   40   │ Potential problems                │
│ info     │   30   │ Normal operations                 │
│ debug    │   20   │ Detailed debugging                │
│ trace    │   10   │ Very detailed tracing             │
│ silent   │   --   │ Disable all logging               │
└──────────┴────────┴──────────────────────────────────┘
```

```js
// Custom levels
const logger = pino({
  level: 'info',
  customLevels: {
    audit: 35,  // between info (30) and warn (40)
  },
});

logger.audit({ userId: 'u_123', action: 'delete_account' }, 'Audit event');
```

## Pretty Printing for Development

Pino's raw JSON output is optimized for machines. For development, use pino-pretty:

```js
import pino from 'pino';

const logger = pino({
  level: 'debug',
  transport: process.env.NODE_ENV !== 'production'
    ? {
        target: 'pino-pretty',
        options: {
          colorize: true,
          translateTime: 'HH:MM:ss',
          ignore: 'pid,hostname',
          singleLine: false,
        },
      }
    : undefined,
});

// Development output:
// 10:30:00 INFO: Server started
//     port: 3000

// Production output (raw JSON):
// {"level":30,"time":1710500000000,"port":3000,"msg":"Server started"}
```

## Child Loggers

Child loggers add persistent context without copying the parent:

```js
import pino from 'pino';

const logger = pino({ level: 'info' });

// Module-level child loggers
const authLogger = logger.child({ module: 'auth' });
const dbLogger = logger.child({ module: 'database' });

authLogger.info({ userId: 'u_123' }, 'Login successful');
// {"level":30,"time":...,"module":"auth","userId":"u_123","msg":"Login successful"}

dbLogger.warn({ query: 'slow query', duration: 5200 }, 'Slow query detected');
// {"level":40,"time":...,"module":"database","query":"slow query","duration":5200,"msg":"Slow query detected"}

// Request-scoped child loggers
function requestMiddleware(req, res, next) {
  req.log = logger.child({
    requestId: req.headers['x-request-id'] || crypto.randomUUID(),
    method: req.method,
    url: req.url,
  });
  next();
}
```

## Serializers

Serializers control how objects are converted to JSON. This is critical for performance and security:

```js
import pino from 'pino';

const logger = pino({
  serializers: {
    // Custom error serializer (redact sensitive info)
    err: pino.stdSerializers.err,  // built-in: includes message, stack, type

    // Custom request serializer
    req: (req) => ({
      method: req.method,
      url: req.url,
      headers: {
        host: req.headers.host,
        'user-agent': req.headers['user-agent'],
        // Deliberately exclude authorization, cookie headers
      },
    }),

    // Custom response serializer
    res: (res) => ({
      statusCode: res.statusCode,
      headers: {
        'content-type': res.getHeader('content-type'),
        'content-length': res.getHeader('content-length'),
      },
    }),

    // Redact user objects
    user: (user) => ({
      id: user.id,
      role: user.role,
      // Omit email, password hash, etc.
    }),
  },
});

// Serializers are triggered by matching key names
logger.info({ req, res, user }, 'Request processed');
```

## Pino with Express: pino-http

```bash
npm install pino-http
```

```js
import express from 'express';
import pino from 'pino';
import pinoHttp from 'pino-http';

const logger = pino({
  level: process.env.LOG_LEVEL || 'info',
});

const app = express();

// Automatic request/response logging
app.use(pinoHttp({
  logger,

  // Custom request ID
  genReqId: (req) => req.headers['x-request-id'] || crypto.randomUUID(),

  // Custom log level based on status code
  customLogLevel: (req, res, err) => {
    if (res.statusCode >= 500 || err) return 'error';
    if (res.statusCode >= 400) return 'warn';
    return 'info';
  },

  // Custom success message
  customSuccessMessage: (req, res) => {
    return `${req.method} ${req.url} completed`;
  },

  // Custom error message
  customErrorMessage: (req, res, err) => {
    return `${req.method} ${req.url} failed: ${err.message}`;
  },

  // Customize what gets logged from req/res
  serializers: {
    req: (req) => ({
      method: req.method,
      url: req.url,
      query: req.query,
      params: req.params,
    }),
    res: (res) => ({
      statusCode: res.statusCode,
    }),
  },

  // Redact sensitive headers
  redact: {
    paths: ['req.headers.authorization', 'req.headers.cookie'],
    censor: '[REDACTED]',
  },
}));

// Use req.log in route handlers
app.get('/api/users/:id', (req, res) => {
  req.log.info({ userId: req.params.id }, 'Fetching user');
  // ...
});

app.listen(3000, () => {
  logger.info({ port: 3000 }, 'Server started');
});
```

## Redaction

Pino has built-in redaction via fast-redact, which is much faster than post-processing:

```js
const logger = pino({
  redact: {
    paths: [
      'password',
      'secret',
      'token',
      'req.headers.authorization',
      'req.headers.cookie',
      'user.email',
      'creditCard',
      '*.ssn',           // wildcard: any object's ssn field
    ],
    censor: '[REDACTED]',
  },
});

logger.info({
  user: { id: 'u_123', email: 'test@example.com', name: 'Alice' },
  token: 'eyJhbG...',
}, 'User action');
// user.email and token will show as '[REDACTED]'
```

## Transports (Pino v7+)

Pino transports run in worker threads, keeping the main thread fast:

```js
import pino from 'pino';

const logger = pino({
  level: 'info',
  transport: {
    targets: [
      // Pretty print to console in development
      {
        target: 'pino-pretty',
        level: 'debug',
        options: { colorize: true, translateTime: true },
      },
      // Write to file
      {
        target: 'pino/file',
        level: 'info',
        options: { destination: './logs/app.log', mkdir: true },
      },
      // Write errors to separate file
      {
        target: 'pino/file',
        level: 'error',
        options: { destination: './logs/error.log', mkdir: true },
      },
    ],
  },
});
```

## Pino with NestJS

NestJS has excellent Pino integration via nestjs-pino:

```bash
npm install nestjs-pino pino-http pino-pretty
```

```js
import { Module } from '@nestjs/common';
import { LoggerModule } from 'nestjs-pino';

@Module({
  imports: [
    LoggerModule.forRoot({
      pinoHttp: {
        level: process.env.LOG_LEVEL || 'info',
        transport: process.env.NODE_ENV !== 'production'
          ? { target: 'pino-pretty', options: { colorize: true } }
          : undefined,
        redact: ['req.headers.authorization'],
        customLogLevel: (req, res, err) => {
          if (res.statusCode >= 500) return 'error';
          if (res.statusCode >= 400) return 'warn';
          return 'info';
        },
      },
    }),
  ],
})
export class AppModule {}

// In a service
import { Injectable, Logger } from '@nestjs/common';
import { InjectPinoLogger, PinoLogger } from 'nestjs-pino';

@Injectable()
export class UserService {
  constructor(private readonly logger: PinoLogger) {
    this.logger.setContext('UserService');
  }

  async findUser(id: string) {
    this.logger.info({ userId: id }, 'Finding user');
    // ...
  }
}
```

## Async-Safe Logging and Process Exit

Pino's async transports buffer logs. Ensure logs are flushed before process exit:

```js
import pino from 'pino';

const logger = pino({
  level: 'info',
  transport: {
    target: 'pino/file',
    options: { destination: './logs/app.log' },
  },
});

// Flush logs on graceful shutdown
const destination = pino.destination('./logs/app.log');

process.on('SIGTERM', () => {
  logger.info('Shutting down gracefully');
  logger.flush();  // synchronous flush
  // or with async destination:
  // destination.flushSync();
  process.exit(0);
});

// For final logging (pino.final creates a special logger)
const finalLogger = pino.final(logger, (err, finalLogger, evt) => {
  finalLogger.info(`${evt} caught`);
  if (err) finalLogger.error(err, 'error caused exit');
  process.exit(err ? 1 : 0);
});

process.on('uncaughtException', (err) => finalLogger(err, 'uncaughtException'));
process.on('unhandledRejection', (err) => finalLogger(err, 'unhandledRejection'));
```

## Winston vs Pino Decision Guide

```
┌─────────────────────────────────────────────────────┐
│              Choose Pino when:                       │
│  - Performance is critical (high-throughput APIs)    │
│  - You want minimal overhead on the event loop       │
│  - Your log pipeline handles JSON natively           │
│  - You prefer convention over configuration          │
│                                                     │
│              Choose Winston when:                    │
│  - You need multiple complex transports              │
│  - You want maximum format flexibility               │
│  - You need custom log levels or formats             │
│  - Your team is already familiar with it             │
│                                                     │
│              For most new Node.js projects:          │
│  Pino is the recommended choice.                    │
└─────────────────────────────────────────────────────┘
```

## Summary

Pino is a high-performance structured JSON logger that minimizes impact on your application's event loop. Its worker-thread transports, built-in redaction, and pino-http Express integration make it the best choice for performance-sensitive Node.js backends. Use child loggers for contextual data, serializers for controlling output shape, and pino-pretty for readable development output. In production, pipe raw JSON to your log aggregation system for maximum efficiency.

7.5.3.body:
# Prometheus: Metrics Collection and Grafana Dashboards

## Why Application Metrics Matter

Logs tell you what happened. Metrics tell you how your system is performing right now. While logs are invaluable for debugging specific incidents, metrics give you the high-level view: how many requests per second, what is the 99th percentile latency, how much memory is being used, how many database connections are active.

Prometheus is the industry-standard metrics system. It uses a pull-based model: your application exposes a `/metrics` endpoint, and Prometheus scrapes it periodically.

```
┌────────────┐    scrape /metrics    ┌────────────────┐    query     ┌─────────────┐
│  Your App  │ ◄──────────────────── │   Prometheus    │ ◄────────── │   Grafana    │
│  (Node.js) │    every 15-30s       │   (time-series  │             │ (dashboards) │
│            │                       │    database)    │             │              │
│ /metrics   │                       │                │             │              │
└────────────┘                       └────────────────┘             └─────────────┘

     Expose                              Store &                      Visualize
     metrics                             aggregate                    & alert
```

## Installing prom-client

```bash
npm install prom-client
```

prom-client is the official Prometheus client library for Node.js.

## Metric Types

Prometheus has four core metric types:

```
┌────────────────┬──────────────────────────────────────────────────┐
│ Type           │ Description and Use Case                         │
├────────────────┼──────────────────────────────────────────────────┤
│ Counter        │ Monotonically increasing value                   │
│                │ Use: total requests, errors, bytes sent          │
│                │ Operations: inc()                                │
├────────────────┼──────────────────────────────────────────────────┤
│ Gauge          │ Value that can go up or down                     │
│                │ Use: active connections, queue size, temperature │
│                │ Operations: set(), inc(), dec()                  │
├────────────────┼──────────────────────────────────────────────────┤
│ Histogram      │ Samples observations in configurable buckets     │
│                │ Use: request latency, response sizes             │
│                │ Operations: observe()                            │
│                │ Provides: count, sum, bucket distributions       │
├────────────────┼──────────────────────────────────────────────────┤
│ Summary        │ Calculates quantiles over sliding time window    │
│                │ Use: request latency (when you need percentiles) │
│                │ Operations: observe()                            │
│                │ Provides: count, sum, quantile values            │
└────────────────┴──────────────────────────────────────────────────┘
```

## Basic Setup with Default Metrics

```js
import express from 'express';
import client from 'prom-client';

// Collect default Node.js metrics (CPU, memory, event loop, GC)
const register = new client.Registry();
client.collectDefaultMetrics({
  register,
  prefix: 'myapp_',    // prefix all default metrics
  gcDurationBuckets: [0.001, 0.01, 0.1, 1, 2, 5],
});

const app = express();

// Expose metrics endpoint
app.get('/metrics', async (req, res) => {
  res.set('Content-Type', register.contentType);
  res.end(await register.metrics());
});

app.listen(3000);
```

Default metrics include:
- `process_cpu_seconds_total` -- CPU usage
- `process_resident_memory_bytes` -- Memory usage
- `nodejs_heap_size_total_bytes` -- V8 heap size
- `nodejs_active_handles_total` -- Active libuv handles
- `nodejs_eventloop_lag_seconds` -- Event loop delay
- `nodejs_gc_duration_seconds` -- Garbage collection duration

## Counter: Tracking Total Requests and Errors

```js
import client from 'prom-client';

const register = new client.Registry();

// Total HTTP requests counter
const httpRequestsTotal = new client.Counter({
  name: 'http_requests_total',
  help: 'Total number of HTTP requests',
  labelNames: ['method', 'route', 'status_code'],
  registers: [register],
});

// Total errors counter
const errorsTotal = new client.Counter({
  name: 'errors_total',
  help: 'Total number of errors',
  labelNames: ['type', 'module'],
  registers: [register],
});

// Usage in middleware
app.use((req, res, next) => {
  res.on('finish', () => {
    httpRequestsTotal.inc({
      method: req.method,
      route: req.route?.path || req.path,
      status_code: res.statusCode,
    });

    if (res.statusCode >= 500) {
      errorsTotal.inc({ type: 'http_5xx', module: 'api' });
    }
  });
  next();
});
```

Prometheus output:
```
# HELP http_requests_total Total number of HTTP requests
# TYPE http_requests_total counter
http_requests_total{method="GET",route="/api/users",status_code="200"} 1542
http_requests_total{method="POST",route="/api/users",status_code="201"} 89
http_requests_total{method="GET",route="/api/users/:id",status_code="404"} 23
```

## Gauge: Active Connections and Queue Size

```js
const activeConnections = new client.Gauge({
  name: 'active_connections',
  help: 'Number of active connections',
  registers: [register],
});

const queueSize = new client.Gauge({
  name: 'job_queue_size',
  help: 'Number of jobs waiting in queue',
  labelNames: ['queue_name'],
  registers: [register],
});

const dbPoolSize = new client.Gauge({
  name: 'db_pool_connections',
  help: 'Database connection pool status',
  labelNames: ['state'],  // 'active', 'idle', 'waiting'
  registers: [register],
});

// Track WebSocket connections
wss.on('connection', (ws) => {
  activeConnections.inc();
  ws.on('close', () => activeConnections.dec());
});

// Periodically update pool metrics
setInterval(async () => {
  const poolStats = await db.pool.stats();
  dbPoolSize.set({ state: 'active' }, poolStats.active);
  dbPoolSize.set({ state: 'idle' }, poolStats.idle);
  dbPoolSize.set({ state: 'waiting' }, poolStats.waiting);
}, 5000);
```

## Histogram: Request Latency Distribution

Histograms are the most important metric type for understanding API performance:

```js
const httpRequestDuration = new client.Histogram({
  name: 'http_request_duration_seconds',
  help: 'Duration of HTTP requests in seconds',
  labelNames: ['method', 'route', 'status_code'],
  buckets: [0.005, 0.01, 0.025, 0.05, 0.1, 0.25, 0.5, 1, 2.5, 5, 10],
  registers: [register],
});

// Middleware to time requests
app.use((req, res, next) => {
  const end = httpRequestDuration.startTimer();

  res.on('finish', () => {
    end({
      method: req.method,
      route: req.route?.path || req.path,
      status_code: res.statusCode,
    });
  });

  next();
});

// Custom operation timing
const dbQueryDuration = new client.Histogram({
  name: 'db_query_duration_seconds',
  help: 'Duration of database queries in seconds',
  labelNames: ['operation', 'table'],
  buckets: [0.001, 0.005, 0.01, 0.05, 0.1, 0.5, 1, 5],
  registers: [register],
});

async function findUser(id) {
  const end = dbQueryDuration.startTimer();
  try {
    const user = await db.user.findUnique({ where: { id } });
    end({ operation: 'findUnique', table: 'users' });
    return user;
  } catch (err) {
    end({ operation: 'findUnique', table: 'users' });
    throw err;
  }
}
```

Prometheus output:
```
