# TYPE http_request_duration_seconds histogram
http_request_duration_seconds_bucket{method="GET",route="/api/users",status_code="200",le="0.005"} 120
http_request_duration_seconds_bucket{method="GET",route="/api/users",status_code="200",le="0.01"} 350
http_request_duration_seconds_bucket{method="GET",route="/api/users",status_code="200",le="0.025"} 480
http_request_duration_seconds_bucket{method="GET",route="/api/users",status_code="200",le="0.05"} 510
http_request_duration_seconds_bucket{method="GET",route="/api/users",status_code="200",le="+Inf"} 520
http_request_duration_seconds_sum{method="GET",route="/api/users",status_code="200"} 8.45
http_request_duration_seconds_count{method="GET",route="/api/users",status_code="200"} 520
```

## Summary: Percentile Calculation

```js
const requestDurationSummary = new client.Summary({
  name: 'http_request_duration_summary_seconds',
  help: 'Request duration percentiles',
  labelNames: ['method', 'route'],
  percentiles: [0.5, 0.9, 0.95, 0.99],
  maxAgeSeconds: 300,  // 5-minute sliding window
  ageBuckets: 5,
  registers: [register],
});
```

Histograms vs Summaries:
- Histograms: aggregatable across instances, uses more memory, server-side percentile calculation
- Summaries: per-instance percentiles, cannot be aggregated, client-side calculation
- Recommendation: use Histograms for most cases

## Complete Express Metrics Middleware

```js
import express from 'express';
import client from 'prom-client';

const register = new client.Registry();
client.collectDefaultMetrics({ register, prefix: 'myapp_' });

// Metrics
const httpRequestsTotal = new client.Counter({
  name: 'myapp_http_requests_total',
  help: 'Total HTTP requests',
  labelNames: ['method', 'route', 'status_code'],
  registers: [register],
});

const httpRequestDuration = new client.Histogram({
  name: 'myapp_http_request_duration_seconds',
  help: 'HTTP request duration in seconds',
  labelNames: ['method', 'route', 'status_code'],
  buckets: [0.005, 0.01, 0.025, 0.05, 0.1, 0.25, 0.5, 1, 2.5, 5, 10],
  registers: [register],
});

const httpRequestSize = new client.Histogram({
  name: 'myapp_http_request_size_bytes',
  help: 'HTTP request body size in bytes',
  labelNames: ['method', 'route'],
  buckets: [100, 1000, 10000, 100000, 1000000],
  registers: [register],
});

const activeRequests = new client.Gauge({
  name: 'myapp_http_active_requests',
  help: 'Number of active HTTP requests',
  registers: [register],
});

// Metrics middleware
function metricsMiddleware(req, res, next) {
  activeRequests.inc();
  const end = httpRequestDuration.startTimer();

  // Track request size
  const contentLength = parseInt(req.headers['content-length'] || '0', 10);
  if (contentLength > 0) {
    httpRequestSize.observe(
      { method: req.method, route: req.route?.path || req.path },
      contentLength
    );
  }

  res.on('finish', () => {
    const route = req.route?.path || req.path;
    const labels = {
      method: req.method,
      route,
      status_code: res.statusCode,
    };

    httpRequestsTotal.inc(labels);
    end(labels);
    activeRequests.dec();
  });

  next();
}

// Application
const app = express();
app.use(express.json());
app.use(metricsMiddleware);

// Metrics endpoint (do NOT apply metricsMiddleware to this route)
app.get('/metrics', async (req, res) => {
  res.set('Content-Type', register.contentType);
  res.end(await register.metrics());
});

// Business routes
app.get('/api/users', async (req, res) => {
  const users = await findUsers();
  res.json(users);
});

app.listen(3000);
```

## Custom Business Metrics

```js
// Track business-level events
const ordersPlaced = new client.Counter({
  name: 'myapp_orders_placed_total',
  help: 'Total orders placed',
  labelNames: ['payment_method', 'currency'],
  registers: [register],
});

const orderAmount = new client.Histogram({
